import React from "react";

import { ProSidebar, SidebarHeader, SidebarFooter, SidebarContent } from 'react-pro-sidebar';
import Buttons from "../button/button";
import "./sidebar_style.css";
const Sidebar = ({image,collapsed,toggled,handleToggleSidebar,HandleCollapsedChange}) => {
            return (
            <>
            <ProSidebar
                        image={image}
                        collapsed={collapsed}
                        toggled={toggled}
                        breakPoint="md"
                        onToggle={handleToggleSidebar}
                        onCollapse={HandleCollapsedChange}

            >
                        <SidebarHeader>
                             
                        </SidebarHeader>

                        <SidebarContent>

                         </SidebarContent>
                        <SidebarFooter>

                        </SidebarFooter>

            </ProSidebar>
            <div className="sidebar">

                        <div className="side_list">
                                    <Buttons value="Dashboard" />
                                    <Buttons value="Users" />
                                    <Buttons value="Products" />
                                    <Buttons value="Transactions" />
                                    <Buttons value="Reports" />
                                    <Buttons value="Manage" />
                                    <Buttons value="Settings" />
                                    <Buttons value="Logout" />

                        </div>
                        <div className="profile">
                                    <img  className="profile_img" src="" alt=""  />
                                    <p className="profile_name">John Doe</p>
                        </div>
                        </div>

            </>
            );
            }

export default Sidebar;
